// ReadMoreLink.js

import React from "react";
import { Link } from "gatsby";

export const ReadMoreLink = ({ slug, pType, extraClass = "" }) => (
  <>
    <Link
      to={slug ? `/${pType}/${slug}` : `/${pType}`}
      className={`g-action-link ${extraClass}`}
    >
      Read more ...
    </Link>
  </>
);
