import React from "react";

export const ShowMoreButton = ({ isExpanded, toggleExpand }) => {
  const handleKeyDown = (e) => {
    if (e.key === "Enter") {
      toggleExpand();
    }
  };

  return (
    <>
      {" "}
      <span
        onClick={toggleExpand}
        onKeyDown={handleKeyDown}
        role="button"
        tabIndex={0}
        className="g-expand-text"
        title={isExpanded ? "less" : "more"}
      >
        {isExpanded ? " less" : " more"}
      </span>
    </>
  );
};
